#include <stdio.h>
int main() {
    int n, k, l, c, d;
    scanf("%d %d %d %d %d", &n, &k, &l, &c, &d);
    int x = (k * l) / (n * c);
    int y = d / n;
    printf("%d\n", (x < y) ? x : y);
    return 0;
}

